var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"또 온다! 이번엔 대형 마물이야!","JPN":"また来るぞ！　今度は大型だ！","ENG":"They're coming! It's a large monster this time!","TWN":"又來了！這次是大型怪物！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"민가 쪽으로 돌진한다! 저 안에 대피한 사람들이 있어!","JPN":"民家方面に突進していくぞ！　あの中には避難民たちがいる！","ENG":"It's charging toward the residential area! The evacuated villagers are in there!","TWN":"往住家的方向衝！那裡面有避難的人！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"큭! 몇 번이나 맞혔는데 왜 아직도 멈추질 않는 거야?","JPN":"くっ！　何度も当てているのに、どうして止まらないの！？","ENG":"Kgh! Why won't it stop even after I've already hit it this much?","TWN":"唔！明明已經打中好幾次，為什麼還不停下來？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"제가 막을게요!","JPN":"私が食い止めます！","ENG":"I'll stop it!","TWN":"我來吧！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"},"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"えっ……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"},"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"잠깐…! 몸으로 직접 막을 생각…?!","JPN":"ちょっと待って……！　まさか直接身体で止める気……！？","ENG":"Wait...! You're not thinking of blocking it with your body–?!","TWN":"等等…！你是想直接用身體去擋…？！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"},"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"꺄아악!","JPN":"きゃああっ！","ENG":"AHHHH!","TWN":"嚇啊啊！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"저 바보가…!","JPN":"あのバカ……！","ENG":"That idiot...!","TWN":"那個傻瓜…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_03"},{"id":"L19_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"이런! 건물이 무너진다!","JPN":"しまった、建物が崩れるぞ！","ENG":"Watch out! The building's about to fall!","TWN":"糟糕！房子要垮了！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"피해규모는?","JPN":"被害状況は？","ENG":"How's the damage looking?","TWN":"損失規模如何？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"치료가 필요한 사람들은 모두 이송했습니다.","JPN":"治療すべき怪我人は全員移送完了しました。","ENG":"We've transported everyone who needs treatment.","TWN":"有二個人受傷，目前已送醫治療。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"민가 두 채가 무너지면서 안에 있던 사람들이 다쳤지만…","JPN":"民家が二軒倒壊し、中にいた人は怪我をしてしまいましたが……","ENG":"Two houses have collapsed, and the people in there were injured, but...","TWN":"二棟民宅倒塌，雖然裡面的人有受傷…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"성자님이 몸을 던져 막지 않았다면, 부상으로 끝나진 않았을 겁니다.","JPN":"聖者様が身を投じて止めてくださらなければ、怪我だけじゃ済まなかったはずです。","ENG":"if the Helgon didn't throw herself to block it, it wouldn't have ended with just injuries.","TWN":"但要不是聖者用肉身去擋，可能就不只是受傷這麼簡單了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"전 괜찮아요. 다른 분들이 무사해서 다행이네요.","JPN":"私のことは気にしないでください。他の皆さんがご無事でなによりです。","ENG":"I'm all right. I'm glad the others are safe.","TWN":"我沒事，幸好其他人沒事。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"아얏!","JPN":"いたっ！","ENG":"Ouch!","TWN":"好痛！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"저기요?! 다친 팔을 그렇게 붙들면 아프잖아요?!","JPN":"ちょっと！　負傷した腕をそんなに強く掴まれると痛いじゃないですか！？","ENG":"Hey! It hurts when you grab my injured arm like that!","TWN":"這位小姐？！我的手臂受傷，你還這麼用力抓我的手臂，很痛欸！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"너 미쳤어? 대체 왜 마물 앞으로 달려든 거야?","JPN":"あなた、正気？　いったいどういうつもりで魔物の前に飛び込んだわけ？","ENG":"Are you out of your mind?! Why did you run head first to the monsters?","TWN":"你瘋了嗎？為什麼要跑到怪物面前？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"본인이 죽을 수도 있었다는 건 생각도 안 해?!","JPN":"あなた、死ぬかもしれなかったんだよ？　それを考えなかったの？","ENG":"Didn't it ever cross your mind that you might die?!","TWN":"你沒想過你可能會因此而喪命嗎？！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그게… 사람들이 위험하니 뭐든 해봐야겠단 생각에…","JPN":"えっと……皆さんが危ない状況だったので、なんとかしようと思って……","ENG":"Well... I thought I should do something because people were in danger...","TWN":"因為…情況那麼危險，不管什麼方法都必須試一試…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그래도, 이 정도는 금방 회복하니까 걱정마세요.","JPN":"でも、この程度ならすぐに回復するので、心配しないでください。","ENG":"But don't worry. This will heal in no time.","TWN":"沒事啦，這點小傷，很快就會好的，你不用擔心。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"모르겠어.","JPN":"わからない。","ENG":"I don't know.","TWN":"你是誰。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"蛤？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"넌 뭐하는 녀석인지 모르겠다고.","JPN":"あなたがどんな人間なのか全然わからない。","ENG":"I can't seem to figure you out.","TWN":"你到底是誰？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린을 악마 취급하는 무례한 외지인이, 왜 그렇게까지 우리 일에 목숨을 건 거야?","JPN":"マーリンを悪魔呼ばわりするような失礼極まりないよそ者が、どうしてあたしたちのために命までかけてくれたの？","ENG":"You're a rude outsider who thinks Merlin is a devil. But then, why are you risking your life for us?","TWN":"一個沒禮貌說梅林是魔鬼的外地人，卻奮不顧身地救我們，這是為什麼？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그야… 약자를 구하는 게 성자의 의무니까요…?","JPN":"それは……弱い者を助けるのが聖者の義務……ですから……？","ENG":"That's because... it's a Helgon's duty to protect the weak...?","TWN":"因為…鋤強扶弱是聖者的任務…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…짜증나.","JPN":"……気に入らない。","ENG":"...You're so annoying.","TWN":"…討厭。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"뭐지?","JPN":"えっ？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"내가 화나게 했나…?","JPN":"怒らせてしまったかな……？","ENG":"Did I anger her...?","TWN":"我惹你生氣了嗎…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_QM","text":{"KOREA":"네가 이해하렴.","JPN":"アナタが理解してあげなさい。","ENG":"Please excuse her.","TWN":"你別在意。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"자기 앞에서 누가 다치는 걸 정말 무서워하는 아이거든.","JPN":"自分の目の前で、誰かが傷つくのを誰よりも恐れる子なの。あの子は。","ENG":"That child is terrified of anyone getting hurt in front of her.","TWN":"她很不喜歡看到有人在她眼前受傷。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"당신은…?","JPN":"あなたは……？","ENG":"Who are you...?","TWN":"你是…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"가끔 연명장치에 부작용을 일으키는 케이스가 있긴 한데.","JPN":"稀に延命装置を使ったあと、副作用を引き起こすことがあるのだけれど。","ENG":"There are some cases of the life support device having side effects.","TWN":"接受續命裝置手術的人當中，也是有會引起副作用的少數案例。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"시술을 받고도 잘 싸운 걸 보면, 다행히 부작용은 없나 보네.","JPN":"施術を受けてから、その身体で問題なく戦えたってことは、幸い副作用が起きていないみたいね。","ENG":"But seeing how you are fighting well after receiving treatment, it appears you have none.","TWN":"看你手術完還能戰鬥，應該是沒有產生副作用吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"당신이군요. 절 치료해준 멀린이라는 분이.","JPN":"あなたなんですね。私を治療したマーリンという方は。","ENG":"It's you. You're the one who treated me. Merlin.","TWN":"原來就是你，你就是替我治療的梅林。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"귀염둥이가 벌써 내 소개를 해준 거니? 기특해라.","JPN":"可愛子ちゃんがもうアタシのことを紹介したようね？　嬉しいわ。","ENG":"Did cutie already introduce me to you? How thoughtful of her.","TWN":"小可愛跟你提過我嗎？真乖～"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"너도 한 잔 할래?","JPN":"アナタも一杯どう？","ENG":"Care to have a drink?","TWN":"你也來一杯嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"이건… 술인데요?","JPN":"これは……お酒？","ENG":"But isn't that... alcohol?","TWN":"這是…酒？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"왜? 싫어하니?","JPN":"どうしたの？　苦手かしら？","ENG":"Hmm? Not your taste?","TWN":"怎麼？不喜歡嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"싫어한다기 보단…","JPN":"いいえ、苦手というか……","ENG":"It's not that, but...","TWN":"也不是不喜歡…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"술은 한 모금만 마셔도 정신을 잃거든요.","JPN":"お酒は一滴でも飲むと、気を失ってしまうんです。","ENG":"I lose consciousness if I even have a sip of it.","TWN":"只是我只要喝一滴酒就會失去意識。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그래? 이 좋은 걸 마시지 못하다니. 안타까워라.","JPN":"そうなの？　こんな素晴らしいものが飲めないなんて、可哀想ね。","ENG":"Is that so? What a pity that you cannot drink something this stupendous.","TWN":"是嗎？這麼好的東西，你竟然沒辦法喝，真是可惜。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"포도라도 먹을래? 오늘 수확한 거야.","JPN":"ブドウでも食べる？　今日収穫したばかりのものよ。","ENG":"Then, how about some grapes? We just harvested some.","TWN":"那還是要來點葡萄？是今天剛採收的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"앗, 그건 좋아해요. 감사합니다.","JPN":"あっ、それは大好物です。ありがとうございます。","ENG":"Oh, I like those. Thank you.","TWN":"喔，這個好，謝謝。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"괜찮다면, 네 이야기를 들려주지 않을래?","JPN":"もしよかったら、アナタの話を聞かせてくれるかしら？","ENG":"If it is all right with you, could I hear your story?","TWN":"你可以，告訴我你的事嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"동토 너머의 이야긴 좀처럼 접하기 힘들거든.","JPN":"凍土より向こう側の話は、滅多に聞けるものじゃなくてね。","ENG":"Stories from across the gelid lands are hard to come by.","TWN":"很難得可以聽到凍土另一邊的事呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"아…","JPN":"あ……","ENG":"Oh...","TWN":"呃…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"전 엘리시온이라는 곳에서 왔어요.","JPN":"私はエリシオンという場所から来ました。","ENG":"I'm from a place called Elysion.","TWN":"我來自一個叫艾利森的地方。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"옛 선조들이 탑을 지어 역병을 몰아내고 세운 나라죠.","JPN":"大昔の先祖たちが塔を築き上げ、疫病を追い払い建てた国です。","ENG":"It's a country my ancestors built by erecting a tower to repel the plague.","TWN":"祖先們在那裡建立國家，並且築了一座高塔來隔離瘟疫。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"탑으로 역병을 몰아냈다고?","JPN":"塔を立てて疫病を追い払った？","ENG":"A tower repelling the plague?","TWN":"築一座高塔來隔離瘟疫嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"네, 그 탑을 태양문이라고 부르는데 거기엔 아발론의 성유물이 보관되어 있거든요.","JPN":"はい、その塔は太陽の門と呼ばれるもので、そこにはアバロンの聖遺物が保管されています。","ENG":"Yes. It's called the Solar Gate, and the Holy Relic of Avalon is stored there.","TWN":"沒錯，那座塔就叫作太陽門，裡面保管著阿瓦隆的聖遺物。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"역사가들 말로는 그 탑이 아침해가 제일 먼저 떠오르는 곳이라 그런 이름이 붙었대요.","JPN":"歴史家たちによると、その塔は朝日が最も初めに昇ってくる場所だったので、そんな名前がつけられたんだそうです。","ENG":"Historians say the tower got its name because it is where the morning sun first rises.","TWN":"根據歷史學家的記述，那座塔是第一道曙光升起的地方，因而得名。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"태양문이라…","JPN":"太陽の門……","ENG":"Solar Gate, you say...","TWN":"太陽門…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"제법 그럴싸한 이름이네.","JPN":"それはぴったりな名前ね。","ENG":"What a befitting name.","TWN":"很不錯的名字呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그곳에서 넌 어떤 일을 했는데?","JPN":"アナタはそこでどんなことをしていたの？","ENG":"And what did you do over there?","TWN":"那你是做什麼的？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"전 그곳에서 자랑스러운 순례단의 일원이었어요.","JPN":"私は誇り高き巡礼団の一員でした。","ENG":"I was a proud member of the pilgrimage.","TWN":"我是榮耀朝聖團的一員。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"순례단의 목적은 재능이 있는 성자들을 모아, 마왕을 토벌하는 거죠.","JPN":"巡礼団の目的は、才能ある聖者を集め、魔王を討伐すること。","ENG":"The pilgrimage's objective is to gather talented Helgons and defeat the Demon Lord.","TWN":"朝聖團是一群有能力的聖者所組成的，目的在討伐魔王。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"역병의 원흉인 마왕이 사라지면, 세상은 다시 평화로워질 테니까요.","JPN":"疫病の元凶である魔王がいなくなれば、世界を再び平和にできると。","ENG":"Once the Demon Lord, the root of the plague, is gone, the world will be at peace again.","TWN":"因為魔王是瘟疫的元兇，只要魔王消失，世界就能夠恢復平靜。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"마왕을 없애면 역병이 사라진다라…","JPN":"魔王がいなくれば疫病が消える、ね……","ENG":"Rid of the Demon Lord and the plague will be no more...","TWN":"只要除掉魔王瘟疫就會消失…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"제법 그럴싸하네. 역병의 발생시기는 마왕강림과 시기가 같으니까.","JPN":"辻褄は合いそうな話ね。疫病の発生と、魔王出現はほぼ同時期だったことを考えると。","ENG":"Sounds reasonable. The occurrence of the plague does coincide with the emergence of the Demon Lord.","TWN":"有道理，瘟疫發生的時間點和魔王降臨的時間點一模一樣。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"하지만… 단지 성자들이 힘을 모은다고 해서, 마왕이라는 존재를 꺾을 수 있을까?","JPN":"でも……ただ聖者たちの力を集めたところで、魔王を倒すことができるのかしら？","ENG":"However... can the Demon Lord be defeated with just the powers of Helgons?","TWN":"但是…只要集結聖者們的力量就能夠打敗魔王嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그건…","JPN":"それは……","ENG":"That's… possible.","TWN":"這…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"가능할 거예요. 모두가 그렇게 믿고 있으니까요.","JPN":"できると思います。皆がそう信じていますから。","ENG":"Because we all believe it so.","TWN":"是可能的，大家都深信不疑。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"게다가, 엘리시온에선 누구보다 강한 분이 순례단을 이끌고 계시거든요.","JPN":"それに、エリシオンには誰よりも強いお方が巡礼団を率いているんです。","ENG":"Also, our leader of the pilgrimage is the strongest in all of Elysion.","TWN":"重點是，朝聖團是由艾利森最強的那位在帶領的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그렇게 믿고 있다라.","JPN":"そう信じている、ね。","ENG":"And that is what you believe.","TWN":"你們都深信不疑嗎。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"엘리시온을 일으켜 세운 가능성은… 신앙이구나.","JPN":"エリシオンを立ち上がらせたのは……信仰。","ENG":"The possibilities that led to Elysion's foundation is... faith.","TWN":"原來建立起艾利森的可能性…就是信仰。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"하지만, 믿음이 모든 고난을 해결해주진 못했어요.","JPN":"ただ、信仰が全ての苦難を解決してくれたわけではありませんでした。","ENG":"But faith didn't resolve all hardships.","TWN":"但光是相信，並無法解決所有的困難。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"태양문은 역병을 막아주는 기적이지만… 역병에 걸린 환자들을 당신처럼 치료해주지 못했거든요.","JPN":"太陽の門は疫病を防いでくれる奇跡ですが……すでに疫病にかかった患者を、あなたのように治すことはできませんでしたから。","ENG":"It's a miracle that the Solar Gate fends off the plague... but it can't treat the ill like you have.","TWN":"雖然太陽門可以隔離瘟疫的已經是個神蹟…但我們當中沒有像你一樣可以治療瘟疫的人。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그러니까, 드리고 싶은 부탁이 있어요.","JPN":"だから、ぜひお願いさせていただきたいことがあります。","ENG":"So, I have a favor to ask you.","TWN":"所以，我有件事想拜託你。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"무슨 말을 하고 싶은 지 알아.","JPN":"何を言おうとしているかわかるわ。","ENG":"I already know what you are about to ask.","TWN":"我知道你想說什麼。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"하지만 난 네가 원하는 도움을 줄 수 없어.","JPN":"ただ、残念ながらアタシは何もできない。","ENG":"However, I cannot provide the assistance that you hope.","TWN":"但我無法提供你所需要的幫助。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"부탁드려요!","JPN":"そこをどうかお願いします！","ENG":"Please!","TWN":"拜託你！！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"지금도 엘리시온에선 수많은 사람이 역병으로 고통받고 있을 거예요!","JPN":"今もエリシオンには膨大な数の人々が疫病によって苦しめられているのです！","ENG":"Countless lives are suffering from the plague in Elysion even this second!","TWN":"現在在艾利森還是有需多人為瘟疫所苦！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"당신의 그 치료법만 있으면…!","JPN":"でも、あなたの治療法さえあれば……！","ENG":"If you could treat them...!","TWN":"只要有你的治療技術…！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"내가 널 치료한 건, 널 살려둘 필요가 있었기 때문이야.","JPN":"アタシがアナタを治したのは、生かしておく価値があったからよ。","ENG":"The reason why I treated you is because I needed you alive.","TWN":"我之所以會救你，是因為有必要。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"내 시술엔 그 대가를 감수할 만큼의 가치가 있어야 하니까.","JPN":"アタシの施術は、その代償より価値が上回るときにしか行わないの。","ENG":"My treatment must be worth the risk I am willing to take.","TWN":"我的手術必須付出對應的代價。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"대가라면 제가 치를게요! 엘리시온엔 저 같은 성자들이 많으니까…! 당신들에게 힘이 되어줄 수도 있어요!","JPN":"代償は私が負います！　エリシオンには私と同じ聖者がたくさんいます……あなたの力になってくれるはずです！","ENG":"I'll pay whatever that is! There are many Helgons like me in Elysion...! I'm sure they'll be of help to you!","TWN":"我願意付代價！在艾利森有許多像我一樣的聖者…！我們可以成為你的助力！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그런 대가를 말하는 게 아니야.","JPN":"見返りの話をしているわけじゃないわ。","ENG":"That is not the price I am referring to.","TWN":"我不是指這個。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"네가 말하는 치료법은 한계가 있거든.","JPN":"アタシの治療法には限界があるのよ。","ENG":"The treatment you speak of has its limits.","TWN":"你所說的治療技術是有限的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"한계가… 있다고요?","JPN":"限界……ですか？","ENG":"Limits...?","TWN":"有限…？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"우리 마을의 중심엔 아주 큰 그루터기가 있어.","JPN":"アタシたちの村の中心には、とても巨大な切り株がある。","ENG":"There is a large stump at the center of our village.","TWN":"在村裡的中心有個巨大的木墩，"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그 그루터기의 뿌리엔 거대한 가능성이 맥동하고 있지.","JPN":"その切り株の根には、巨大な可能性としてのエネルギーが脈打っているわ。","ENG":"And huge possibilities pulsate from its roots.","TWN":"而木墩的根上有巨大的可能性在流動。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"내가 지금 이 자리에 있는 것도, 이곳 사람들이 역병의 영향을 받지 않는 것도… 그 힘을 빌린 덕분이야.","JPN":"アタシが今ここにいられるのも、この村人たちが疫病に侵されずに暮らしていられるのも……その力を借りているおかげよ。","ENG":"The reason I am standing in front of you, and why the people here are not affected by the plague... is all due to borrowing its power.","TWN":"我現在之所以能在這個位置，這裡的人之所以不會受到瘟疫的影響…全都要歸功於那股力量。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"세상의 모든 환자에게 호의로 가능성을 베풀 수도 있겠지만, 그렇게 되면 가능성은 순식간에 동나버리고 말겠지.","JPN":"世界中の患者に、その可能性を与えることもできるけど、そんなことをしてしまえば、可能性は一瞬で尽きてしまうわ。","ENG":"I could give possibilities to all the world's patients out of goodwill. But then, the possibilities will deplete in mere seconds.","TWN":"當然也可以出於好意，將可能性用在世界上所有患者的身上，但如此一來可能性就會瞬間耗盡。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"내가 돕지 못한다는 건, 그런 이유야.","JPN":"それが、アタシが依頼を断る理由よ。","ENG":"That is why I cannot help you.","TWN":"這就是我無法提供幫助的原因。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그 물건이 연명장치라 불리는 건….","JPN":"延命装置という名がつけられている所以は……","ENG":"Then the reason you call that a life support device...","TWN":"原來它之所以會稱為續命裝置…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"이 시술이 정상적인 치료가 아니기 때문이군요.","JPN":"この施術は正常な治療ではないからなんですね。","ENG":"is because this treatment is not orthodox.","TWN":"是因為這個手術並非一般的治療方法。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"맞아.","JPN":"そうよ。","ENG":"You are correct.","TWN":"沒錯。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"나무의 가능성을 지속적으로 공급 받지 못하면, 네 역병도 다시 진행될 거야.","JPN":"切り株の根から可能性を続けて提供してもらわないと、アナタの疫病も再び進行することになる。","ENG":"If you are not provided with the tree's constant possibilities, the plague will start spreading within you again.","TWN":"要是木墩無法繼續供應可能性，那你的瘟疫也會再復發。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"역병의 작용을 유예해 온 만큼 아주 빠르게 널 집어삼키겠지.","JPN":"疫病の影響を食い止めている以上、それがなくなれば、アナタの病状はあっという間に悪化してしまうでしょうね。","ENG":"The plague will devour you as quickly as its effects have been delayed.","TWN":"而且一旦復發，反撲的速度也會非常快。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그루터기의 사람들은… 이 사실을 전부 알고 있나요?","JPN":"切り株の人たちは……このことをすべて知っているんでしょうか？","ENG":"Then do the people of this village... know about all of this?","TWN":"木墩的人…都知道這件事嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"모르겠지. 말해준 적이 없으니까.","JPN":"いいえ、アタシからこのことについて話したことはないわ。","ENG":"No, for I have never told them.","TWN":"當然不知道，我從未提過這件事。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"너에게 이 사실을 말해준 건, 네 미움을 사고 싶지 않기 때문이야.","JPN":"アナタにこの事実を伝えたのは、アナタに恨みを持たれたくなかったからよ。","ENG":"I am only telling you so because I do not want you to hate me.","TWN":"我之所以會告訴你，是不希望你因此心生怨恨。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"비밀. 지켜줄 수 있겠지?","JPN":"この秘密を守ってくれるかしら？","ENG":"Keep this between us, can you?","TWN":"你可以，保守秘密吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"어째서 이곳 사람도 아닌 제게 이렇게까지 도움을 주신 거죠?","JPN":"どうしてよそ者の私に、ここまでしてくれるんですか？","ENG":"Why did you help me when I'm not even one of your people?","TWN":"為什麼你要救我這個外人呢？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"말했잖니? 쓸모가 있기 때문이라고.","JPN":"言ったわよね？　その価値があったからよ。","ENG":"Did I not say? I have use for you.","TWN":"我剛說過，因為你有用處。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그 쓸모라는 건… 제가 가진 성자의 힘을 말하는 건가요?","JPN":"その価値というのは……私の聖者としての力のことでしょうか？","ENG":"By saying you have use for me... are you talking about my Helgon powers?","TWN":"你說的用處…是指我身上的聖者力量嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"절반은 맞다고 해둘게.","JPN":"半分はそうだと言っておくわ。","ENG":"Partially.","TWN":"算你答對一半。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"하나 묻고 싶은 게 있어요.","JPN":"一つだけ聞かせてください。","ENG":"Answer me this.","TWN":"我想問你一件事。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"내가 대답해줄 수 있는 거라면, 얼마든지.","JPN":"アタシが答えられるものなら、何でもどうぞ。","ENG":"If it is something I can, gladly.","TWN":"你問吧，我能答就答。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"사람을 역병으로부터 지켜줄 정도로 대단한 힘을 가진 나무가… 왜 이런 동토 한복판에 있는 거죠?","JPN":"人々を疫病から守れるだけの素晴らしい力を持つ樹木が……なぜ凍土の中央に存在するんでしょうか？","ENG":"Why is a tree with tremendous powers that can protect the people from the plague... in the middle of the gelid lands?","TWN":"那個有如此巨大能力，可以讓人不受瘟疫影響的樹木…為何會在凍土的中心？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그루터기는 늘 이 자리에 있었어.","JPN":"切り株はずっとここに存在していたのよ。","ENG":"The Stump has always been here.","TWN":"木墩一直都在那裡，"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"이 세상이 탄생하는 순간부터 말이야.","JPN":"この世界が誕生したその瞬間からね。","ENG":"From the moment the world was born.","TWN":"從創世之初就在。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"세상의 탄생 때부터 있었다니…","JPN":"世界の誕生から存在した……","ENG":"From when the world was born...?","TWN":"從創世之初嗎…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그럼 저 나무가 설마…?","JPN":"ということは、まさかあの樹木は……？","ENG":"Then, that tree is...","TWN":"那該不會是…？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그래.","JPN":"そう。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"세계수.","JPN":"世界樹よ。","ENG":"The World Tree.","TWN":"世界樹。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"네가 역사를 배웠다면, 아발론의 <color=#ffd34c>황금나무</color>라는 표현이 더 익숙하겠지.","JPN":"アナタが歴史を勉強しているなら、アバロンの<color=#ffd34c>黄金の木</color>という呼び名の方が馴染みがあるかもしれないわね。","ENG":"If you have learned your history, the term <color=#ffd34c>Golden Tree</color> of Avalon will be more familiar to you.","TWN":"若是你學過歷史，你比較常聽到的應該是阿瓦隆的<color=#ffd34c>黃金樹</color>。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"황금나무?","JPN":"黄金の木？","ENG":"The Golden Tree?","TWN":"黃金樹？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"하지만, 그건 말도 안 돼요.","JPN":"でも、それはあり得ません。","ENG":"But that's impossible.","TWN":"但這怎麼可能。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"선조들이 아발론을 떠나 엘리시온을 건국한 건, 아발론을 지켜주던 황금나무가 시들었기 때문이라고 들었는데.","JPN":"先祖がアバロンを離れ、エリシオンを建国したのはアバロンを守っていた黄金の木が枯れてしまったからだと学んでいます。","ENG":"I heard the reason my ancestors left Avalon and founded Elysion was because the Golden Tree of Avalon withered away.","TWN":"據我所知，祖先們之所以會離開阿瓦隆建立艾利森，就是因為守護阿瓦隆的黃金樹枯萎的關係。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"제가 배운 역사가 전부 거짓이란 건가요?","JPN":"私が学んだ歴史は、すべて偽りだったということなんですか？","ENG":"Are you telling me that the history I learned was all a lie?","TWN":"你現在的意思是，我之前學過的歷史都是假的嗎？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"역병으로 황금나무가 시든 건 사실이야.","JPN":"疫病によって黄金の木が枯れてしまったのは事実よ。","ENG":"It is true the Golden Tree withered due to the plague.","TWN":"瘟疫確實導致黃金樹枯萎沒錯。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그게 거짓이라면 황금나무가 이런 초라한 그루터기의 모습을 하고 있진 않았겠지.","JPN":"もしそれが偽りだったら、黄金の木がこのようなみすぼらしい切り株の形をしているわけがないもの。","ENG":"If that were false, then the Golden Tree would not be looking like a stump.","TWN":"若這是假的，偉大的黃金樹也會只剩下這麼一個木墩而已。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"대체… 이곳에서 무슨 일이 있었던 거죠?","JPN":"いったい……ここで何があったんですか？","ENG":"What... happened here?","TWN":"這裡…到底發生過什麼事情？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"옛 왕국 아발론이 역병으로 몰락한 뒤, 황금나무의 일곱 요정은 인류 보전이라는 사명을 짊어지고 흩어졌어.","JPN":"古代王国のアバロンが疫病によって滅んだ後、黄金の木の七人の妖精は人類の保存という使命を背負いそれぞれ散らばっていった。","ENG":"After the old kingdom of Avalon fell due to the plague, the seven fairies of the Golden Tree scattered across the lands with a duty to preserve humanity.","TWN":"舊王國阿瓦隆因為瘟疫而沒落後，黃金樹的七位精靈背負起為人類存留餘種的使命後便各自四散。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"어떤 이들은 생명의 호수와 바다로, 또 어떤 이들은 태양과 달의 가호를 받는 산으로.","JPN":"その行先は生命の湖や海、あるいは太陽と月の加護を受ける山だったわ。","ENG":"Some to the lakes and seas of life, others to the mountains blessed by the sun and moon.","TWN":"有些精靈去到生命的湖泊與大海，有些則是去到受到太陽和月亮庇護的山裡。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"네 고향 엘리시온도 그렇게 떠난 요정들 중 하나가 세운 나라일 거야.","JPN":"アナタの故郷エリシオンも、その時の妖精が建国したもののはずよ。","ENG":"Your hometown, Elysion, is a country one of the dispersed fairies had built.","TWN":"你的故鄉艾利森應該就是其中一位精靈所建立的國家。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"엘리시온의 건국사에… 요정이 관여했다고요?","JPN":"エリシオンの建国に……妖精が関わっているんですか？","ENG":"A fairy... was involved in the foundation of Elysion?","TWN":"你是說…精靈也有參與在艾利森的建國史中？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"하지만 그런 얘긴 한 번도 들어본 적 없는 걸요!","JPN":"でも、そんな話は一度も聞いたことがありません！","ENG":"But I've never heard of such a thing!","TWN":"這我從來沒有聽說過！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"모르는 게 당연해.","JPN":"それは当然よ。","ENG":"Of course, you have not.","TWN":"沒聽過是正常的。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"요정들은 동토의 역병을 몰아내기 위해 자신의 심장을 바쳤으니까.","JPN":"妖精たちは凍土の疫病を追い払うために、自分たちの心臓を捧げたの。","ENG":"Because the fairies sacrificed their hearts to rid the plague from the gelid lands.","TWN":"因為精靈們為驅逐凍土的瘟疫而獻出自己的心臟。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"심장을 바친 요정은 신위를 잃고, 모든 인간의 기억에서 잊혀지게 되거든.","JPN":"心臓を捧げた妖精たちは神格を失い、すべての人間たちの記憶から抹消されてしまったのだから。","ENG":"A fairy that has lost its heart loses its status and is erased from the memory of all humans.","TWN":"獻出心臟的精靈就會失去身分，並且從人類的記憶中消失。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"요정의 심장…? 그게 뭐죠?","JPN":"妖精の心臓……？　それはいったい何なんですか？","ENG":"A fairy's heart...? What's that?","TWN":"精靈的心臟…？那是什麼？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"황금나무가 나눠준 무구한 가능성.","JPN":"黄金の木が分け与えた、無限の可能性。","ENG":"It is the endless possibilities given by the Golden Tree.","TWN":"由黃金樹分賜而出的無瑕的可能性，"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"우리는 그걸 <color=#ffd34c>황금가지</color>라고 불러.","JPN":"アタシたちはそれを、<color=#ffd34c>黄金の枝</color>と呼んでいるわ。","ENG":"Here, we call it the <color=#ffd34c>Golden Branch</color>.","TWN":"我們稱之為<color=#ffd34c>金枝</color>。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"황금가지…?","JPN":"黄金の枝……？","ENG":"Golden Branch...?","TWN":"金枝…？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"익숙한 이름이네요.","JPN":"その名には聞き覚えがあります。","ENG":"I've heard that name before.","TWN":"好熟悉的名字。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"역병을 막아주는 태양문의 원동력이 황금가지라는 성유물이라고 배웠거든요.","JPN":"疫病を食い止めてくれる太陽の門のエネルギー源が、黄金の枝という聖遺物であることは学んだことがあります。","ENG":"It's the Holy Relic and power source of the Solar Gate that fends off the plague.","TWN":"我有學過，太陽門隔離瘟疫的動力源就是稱為金枝的聖遺物。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"실제로 본 적은 없지만요.","JPN":"実物を見たことはありませんけど。","ENG":"I've never actually seen it, though.","TWN":"但我從未親眼見過。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"이 그루터기에도 우리가 지키는 황금가지가 있어.","JPN":"この切り株にも、アタシたちが守護している黄金の枝が存在するわ。","ENG":"There is a Golden Branch within this stump that we protect.","TWN":"這木墩裡也有我們保管的金枝。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"역병으로 시든 황금나무가 이렇게나마 살아있는 것도, 그 황금가지의 힘 덕분이지.","JPN":"疫病によって枯れてしまった黄金の木がなんとか生命を維持しているのは、黄金の枝の力によるもの。","ENG":"The Golden Tree, withered by the plague, is still alive thanks to the power of the Golden Branch.","TWN":"因為瘟疫而枯萎黃金樹之所以可以存活到現在，也是拜金枝的力量所賜。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그렇게 만들어진 게 바로 이곳.","JPN":"この場所はそのようにして誕生した。","ENG":"And that is how this place was made.","TWN":"因此才會有現在這個地方，"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"우리가 살아가는 그루터기야.","JPN":"それがアタシたちが暮らす切り株よ。","ENG":"This is the Stump.","TWN":"我們生活的木墩。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};